namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public List<Notification> GetSince(DateTime since)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Timestamp > since).ToList();
        }
    }

    /// <summary>Simulates an external system pushing a new notification.</summary>
    public void SimulateIncoming()
    {
        string[] templates =
        [
            "Server health check passed.",
            "Deployment completed.",
            "New user signed up.",
            "Disk usage alert cleared.",
            "Backup finished successfully.",
            "Security scan completed — no issues.",
        ];

        var message = templates[Random.Shared.Next(templates.Length)];
        lock (_lock)
        {
            _notifications.Add(CreateNotification(message));
        }
    }

    private Notification CreateNotification(string message)
        => new(Interlocked.Increment(ref _nextId), message, DateTime.UtcNow);
}

@page "/notifications"
@rendermode InteractiveServer

@using BlazorNotifications.Services
@implements IAsyncDisposable

@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override void OnInitialized()
    {
        // During SSR the state won't exist yet, so we load from the service.
        // During interactive reconnection the persisted snapshot is restored,
        // avoiding a duplicate fetch.
        _persistSub = ApplicationState.RegisterOnPersisting(PersistNotifications);

        if (ApplicationState.TryTakeFromJson<List<Notification>>(
                nameof(_notifications), out var restored))
        {
            _notifications = restored!;
        }
        else
        {
            _notifications = NotificationSvc.GetAll();
        }
    }

    private Task PersistNotifications()
    {
        ApplicationState.PersistAsJson(nameof(_notifications), _notifications);
        return Task.CompletedTask;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        // OnAfterRender only fires when the component is live in the browser,
        // so the polling loop never runs during the initial static SSR pass.
        _cts = new CancellationTokenSource();
        _ = PollForNotificationsAsync(_cts.Token);

        await Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Determine the high-water mark so we only fetch genuinely new items.
        var since = _notifications.Count > 0
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.MinValue;

        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct)
                       .ConfigureAwait(false);

            // Simulate an external system producing a notification between polls.
            NotificationSvc.SimulateIncoming();

            var newItems = NotificationSvc.GetSince(since);
            if (newItems.Count > 0)
            {
                since = newItems.Max(n => n.Timestamp);
                _notifications.AddRange(newItems);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        _persistSub.Dispose();

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

